package main

import (
	"fmt"
	"sync"
)

type Account struct {
	Balance float64
}

func (a *Account) Deposit(amount float64) {
	a.Balance += amount
}

func (a *Account) Withdraw(amount float64) error {
	if a.Balance < amount {
		return fmt.Errorf("insufficient balance")
	}
	a.Balance -= amount
	return nil
}

var accounts = make(map[string]*Account)
var mu sync.Mutex

func processTransaction(account string, amount float64, operation string) {
	mu.Lock()
	defer mu.Unlock()

	accountBalance, ok := accounts[account]
	if !ok {
		accountBalance = &Account{0}
		accounts[account] = accountBalance
	}

	switch operation {
	case "deposit":
		accountBalance.Deposit(amount)
	case "withdraw":
		err := accountBalance.Withdraw(amount)
		if err != nil {
			fmt.Printf("Error processing transaction for %s: %v\n", account, err)
		}
	default:
		fmt.Printf("Invalid operation: %s\n", operation)
	}
}

func main() {
	go processTransaction("12345", 100.0, "deposit")
	go processTransaction("12345", 50.0, "withdraw")

	var wg sync.WaitGroup
	wg.Add(2)

	done := make(chan bool)
	go func() {
		processTransaction("12345", 200.0, "deposit")
		done <- true
		wg.Done()
	}()

	go func() {
		processTransaction("67890", 50.0, "withdraw")
		done <- true
		wg.Done()
	}()

	go func() {
		<-done
		<-done
		close(done)
		wg.Done()
	}()

	wg.Wait()

	for account, balance := range accounts {
		fmt.Printf("%s: %f\n", account, balance.Balance)
	}
}